    55	void set_ptrs_symb_idx(uint16_t *ptrs_symbols,
    56	                       uint8_t duration_in_symbols,
    57	                       uint8_t start_symbol,
    58	                       uint8_t L_ptrs,
    59	                       uint16_t dmrs_symb_pos)
    60	{
    61	  int i = 0;
    62	  int l_ref = start_symbol;
    63	  const int last_symbol = start_symbol + duration_in_symbols - 1;
    64	  if (L_ptrs == 0) {
    65	    LOG_E(PHY,"bug: impossible L_ptrs\n");
    66	    *ptrs_symbols = 0;
    67	    return;
    68	  }
    69	
    70	  while ((l_ref + i * L_ptrs) <= last_symbol) {
    71	    int is_dmrs_symbol = 0, l_counter;
    72	    for(l_counter = l_ref + i * L_ptrs; l_counter >= max(l_ref + (i - 1) * L_ptrs + 1, l_ref); l_counter--) {
    73	      if((dmrs_symb_pos >> l_counter) & 0x01) {
    74	        is_dmrs_symbol = 1;
    75	        break;
    76	      }
