    79	      l_ref = l_counter;
    80	      i = 1;
    81	      continue;
    82	    }
    83	    *ptrs_symbols = *ptrs_symbols | (1 << (l_ref + i * L_ptrs));
    84	    i++;
    85	  }
    86	}
