   138	uint8_t get_ptrs_symbols_in_slot(uint16_t l_prime_mask, uint16_t start_symb, uint16_t nb_symb)
   139	{
   140	  uint8_t tmp = 0;
   141	  for (int i = start_symb; i <= nb_symb; i++)
   142	    tmp += (l_prime_mask >> i) & 0x01;
   143	  return tmp;
