   146	/* return the position of next ptrs symbol in a slot */
   147	int8_t get_next_ptrs_symbol_in_slot(uint16_t  ptrs_symb_pos, uint8_t counter, uint8_t nb_symb)
   148	{
   149	  for(int8_t symbol = counter; symbol < nb_symb; symbol++) {
   150	    if((ptrs_symb_pos >> symbol) & 0x01) {
   151	      return symbol;
   152	    }
   153	  }
   154	  return -1;
   155	}
