   157	/* get the next nearest estimate from DMRS or PTRS */
   158	int8_t get_next_estimate_in_slot(uint16_t  ptrsSymbPos,uint16_t  dmrsSymbPos, uint8_t counter,uint8_t nb_symb)
   159	{
   160	  int8_t nextPtrs = get_next_ptrs_symbol_in_slot(ptrsSymbPos, counter,nb_symb);
   161	  int8_t nextDmrs = get_next_dmrs_symbol_in_slot(dmrsSymbPos, counter,nb_symb);
   162	  if(nextDmrs == -1) {
   163	    return nextPtrs;
   164	  }
   165	  /* Special case when DMRS is next valid estimation */
   166	  if(nextPtrs == -1) {
   167	    return nextDmrs;
   168	  }
   169	  return (nextPtrs > nextDmrs)?nextDmrs:nextPtrs;
   170	}
